import { Question } from "@/lib/types";

export const questions: Question[] = [
    { id: "y1ht1-001", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 01", yearCreated: 2026, examStyle: false, marks: 1, difficulty: "Foundation", tags: ["null hypothesis", "definition"], questionText: "Define the null hypothesis, \\(H_0\\), in the context of a hypothesis test.", workedSolution: { steps: [{ stepNumber: 1, description: "State the definition of the null hypothesis.", workingLatex: "H_0 \\text{ is the default assumption that there is no change, no difference, or no effect. It specifies a particular value of a population parameter.}", explanation: "The null hypothesis is assumed to be true unless sufficient evidence is found against it." }], finalAnswer: "\\(H_0\\) is the hypothesis that is assumed to be true unless sufficient evidence is found to reject it. It states that there is no change or no effect." } },
    { id: "y1ht1-002", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 02", yearCreated: 2026, examStyle: false, marks: 1, difficulty: "Foundation", tags: ["alternative hypothesis", "definition"], questionText: "Define the alternative hypothesis, \\(H_1\\), in the context of a hypothesis test.", workedSolution: { steps: [{ stepNumber: 1, description: "State the definition of the alternative hypothesis.", workingLatex: "H_1 \\text{ is the hypothesis that is accepted if there is sufficient evidence to reject } H_0. \\text{ It states that there is a change, difference, or effect.}", explanation: "The alternative hypothesis represents what the researcher suspects or is trying to find evidence for." }], finalAnswer: "\\(H_1\\) is the hypothesis that there has been a change, difference, or effect. It is accepted when there is sufficient evidence to reject \\(H_0\\)." } },
    { id: "y1ht1-003", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 03", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["hypotheses", "coin", "notation"], questionText: "A coin is suspected of being biased towards heads. State suitable null and alternative hypotheses for a test of this claim, defining any parameters you use.", workedSolution: { steps: [{ stepNumber: 1, description: "Define the parameter.", workingLatex: "\\text{Let } p \\text{ be the probability of the coin landing heads on a single toss.}", explanation: "" }, { stepNumber: 2, description: "State the null hypothesis.", workingLatex: "H_0 : p = 0.5", explanation: "Under the null hypothesis the coin is fair." }, { stepNumber: 3, description: "State the alternative hypothesis.", workingLatex: "H_1 : p > 0.5", explanation: "The suspicion is that the coin is biased towards heads, so we use a one-tailed (upper) test." }], finalAnswer: "Let \\(p\\) be the probability of heads. \\(H_0 : p = 0.5\\), \\(H_1 : p > 0.5\\)." } },
    { id: "y1ht1-004", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 04", yearCreated: 2026, examStyle: false, marks: 1, difficulty: "Foundation", tags: ["significance level", "definition"], questionText: "Define the significance level of a hypothesis test.", workedSolution: { steps: [{ stepNumber: 1, description: "State the definition.", workingLatex: "\\text{The significance level is the probability of rejecting } H_0 \\text{ when } H_0 \\text{ is in fact true.}", explanation: "It is the threshold probability below which the observed result is considered too unlikely under the null hypothesis, and is denoted by the Greek letter alpha." }], finalAnswer: "The significance level is the probability of incorrectly rejecting \\(H_0\\) when it is true. It is the threshold used to decide whether the evidence against \\(H_0\\) is strong enough." } },
    { id: "y1ht1-005", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 05", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["significance level", "interpretation"], questionText: "Explain what it means to carry out a hypothesis test at the 5% significance level.", workedSolution: { steps: [{ stepNumber: 1, description: "Explain the 5% significance level.", workingLatex: "\\text{A 5\\% significance level means there is a 0.05 probability of rejecting } H_0 \\text{ when } H_0 \\text{ is actually true.}", explanation: "" }, { stepNumber: 2, description: "Relate to the decision rule.", workingLatex: "\\text{We reject } H_0 \\text{ if the probability of obtaining a result as extreme as (or more extreme than) the observed result, assuming } H_0 \\text{ is true, is less than 0.05.}", explanation: "" }], finalAnswer: "At the 5% significance level, we reject \\(H_0\\) if the probability of obtaining the observed result (or more extreme) under \\(H_0\\) is less than 0.05. There is a 5% chance of incorrectly rejecting a true \\(H_0\\)." } },
    { id: "y1ht1-006", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 06", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["one-tailed", "two-tailed", "definition"], questionText: "Explain the difference between a one-tailed test and a two-tailed test.", workedSolution: { steps: [{ stepNumber: 1, description: "Define a one-tailed test.", workingLatex: "\\text{A one-tailed test tests for a change in one specific direction, e.g. } H_1 : p > 0.5 \\text{ or } H_1 : p < 0.5.", explanation: "" }, { stepNumber: 2, description: "Define a two-tailed test.", workingLatex: "\\text{A two-tailed test tests for a change in either direction, e.g. } H_1 : p \\neq 0.5.", explanation: "" }], finalAnswer: "A one-tailed test has an alternative hypothesis that specifies a direction (\\(>\\) or \\(<\\)). A two-tailed test has an alternative hypothesis that allows for change in either direction (\\(\\neq\\))." } },
    { id: "y1ht1-007", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 07", yearCreated: 2026, examStyle: false, marks: 1, difficulty: "Foundation", tags: ["one-tailed", "two-tailed", "identify"], questionText: "A teacher believes that a new teaching method has changed the proportion of students passing an exam, but is unsure whether it has increased or decreased. State whether this test is one-tailed or two-tailed, and justify your answer.", workedSolution: { steps: [{ stepNumber: 1, description: "Identify the type of test.", workingLatex: "\\text{This is a two-tailed test because the teacher suspects the proportion has changed but does not know the direction of the change.}", explanation: "Since the teacher is not specifying whether the proportion has increased or decreased, both directions must be considered." }], finalAnswer: "Two-tailed test, because the teacher suspects a change in either direction." } },
    { id: "y1ht1-008", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 08", yearCreated: 2026, examStyle: false, marks: 1, difficulty: "Foundation", tags: ["test statistic", "definition"], questionText: "Define the term 'test statistic' in the context of a hypothesis test.", workedSolution: { steps: [{ stepNumber: 1, description: "State the definition.", workingLatex: "\\text{The test statistic is the value calculated from the sample data that is used to decide whether to reject } H_0.", explanation: "For example, in a test about a proportion, the test statistic is the number of successes observed in the sample." }], finalAnswer: "The test statistic is a value computed from the sample data that is used to determine whether to reject \\(H_0\\)." } },
    { id: "y1ht1-009", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 09", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["reject", "not reject", "interpretation"], questionText: "Explain what it means to (a) reject \\(H_0\\), and (b) not reject \\(H_0\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Explain rejecting H₀.", workingLatex: "\\text{Rejecting } H_0 \\text{ means the sample data provide sufficient evidence at the chosen significance level to conclude that } H_0 \\text{ is unlikely to be true.}", explanation: "" }, { stepNumber: 2, description: "Explain not rejecting H₀.", workingLatex: "\\text{Not rejecting } H_0 \\text{ means the sample data do not provide sufficient evidence to conclude that } H_0 \\text{ is false. It does not prove } H_0 \\text{ is true.}", explanation: "" }], finalAnswer: "(a) Rejecting \\(H_0\\) means there is sufficient evidence to suggest \\(H_0\\) is not true. (b) Not rejecting \\(H_0\\) means there is insufficient evidence against \\(H_0\\); it does not prove \\(H_0\\) is true." } },
    { id: "y1ht1-010", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 10", yearCreated: 2026, examStyle: false, marks: 2, difficulty: "Foundation", tags: ["hypotheses", "dice", "notation"], questionText: "A board-game player suspects that a six-sided die is biased so that it lands on 6 less often than expected. Let \\(p\\) be the probability of rolling a 6. Write down suitable hypotheses \\(H_0\\) and \\(H_1\\) for a test of this claim.", workedSolution: { steps: [{ stepNumber: 1, description: "State the null hypothesis.", workingLatex: "H_0 : p = \\tfrac{1}{6}", explanation: "Under H₀ the die is fair." }, { stepNumber: 2, description: "State the alternative hypothesis.", workingLatex: "H_1 : p < \\tfrac{1}{6}", explanation: "The player suspects fewer sixes than expected, so we test in the lower tail." }], finalAnswer: "\\(H_0 : p = \\tfrac{1}{6}\\), \\(H_1 : p < \\tfrac{1}{6}\\)." } },
    { id: "y1ht1-011", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 11", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["hypotheses", "context", "one-tailed", "proportion"], questionText: "A manufacturer claims that 10% of the light bulbs it produces are defective. An inspector suspects the true proportion is higher than 10%. She tests a random sample of 30 light bulbs. (a) State suitable hypotheses for this test, defining any parameters used. (b) State whether this is a one-tailed or two-tailed test, giving a reason.", workedSolution: { steps: [{ stepNumber: 1, description: "Define the parameter.", workingLatex: "\\text{Let } p \\text{ be the probability that a randomly selected light bulb is defective.}", explanation: "" }, { stepNumber: 2, description: "State the hypotheses.", workingLatex: "H_0 : p = 0.1 \\quad H_1 : p > 0.1", explanation: "" }, { stepNumber: 3, description: "Identify the type of test.", workingLatex: "\\text{One-tailed test, because the inspector specifically suspects the proportion is higher (not just different).}", explanation: "" }], finalAnswer: "(a) Let \\(p\\) = probability a bulb is defective. \\(H_0 : p = 0.1\\), \\(H_1 : p > 0.1\\). (b) One-tailed, because the inspector suspects the proportion is specifically higher than 10%." } },
    { id: "y1ht1-012", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 12", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["hypotheses", "context", "two-tailed", "proportion"], questionText: "A supermarket claims that 30% of its customers use self-checkout. A researcher wants to test whether the true proportion differs from 30%. (a) Write down suitable hypotheses. (b) State whether the test is one-tailed or two-tailed. (c) The researcher uses a 5% significance level. State what this means in context.", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0 : p = 0.3 \\quad H_1 : p \\neq 0.3", explanation: "where p is the proportion of customers using self-checkout." }, { stepNumber: 2, description: "Identify the type of test.", workingLatex: "\\text{Two-tailed, because the researcher is testing whether the proportion differs (in either direction) from 0.3.}", explanation: "" }, { stepNumber: 3, description: "Explain the 5% significance level in context.", workingLatex: "\\text{There is a 5\\% probability of concluding that the proportion of customers using self-checkout differs from 30\\% when in fact it is 30\\%.}", explanation: "" }], finalAnswer: "(a) \\(H_0 : p = 0.3\\), \\(H_1 : p \\neq 0.3\\). (b) Two-tailed. (c) There is a 5% chance of incorrectly concluding the proportion differs from 30% when it is actually 30%." } },
    { id: "y1ht1-013", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 13", yearCreated: 2026, examStyle: true, marks: 2, difficulty: "Standard", tags: ["why test H0", "philosophy"], questionText: "Explain why, in a hypothesis test, we test \\(H_0\\) rather than trying to prove \\(H_1\\) directly.", workedSolution: { steps: [{ stepNumber: 1, description: "Explain the logic of hypothesis testing.", workingLatex: "\\text{We assume } H_0 \\text{ is true and calculate the probability of the observed data under this assumption.}", explanation: "" }, { stepNumber: 2, description: "Explain why we cannot prove H₁.", workingLatex: "\\text{We cannot prove } H_1 \\text{ directly because an extreme result could occur by chance. Instead, we look for evidence against } H_0.", explanation: "If the data are very unlikely under H₀, we reject H₀ in favour of H₁. This approach controls the probability of making an incorrect conclusion." }], finalAnswer: "We test \\(H_0\\) because we can calculate probabilities under the assumption that \\(H_0\\) is true. We cannot prove \\(H_1\\) directly; instead, we look for sufficient evidence against \\(H_0\\) to reject it in favour of \\(H_1\\)." } },
    { id: "y1ht1-014", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 14", yearCreated: 2026, examStyle: true, marks: 2, difficulty: "Standard", tags: ["conclusion", "in context", "interpretation"], questionText: "A hypothesis test is carried out with \\(H_0 : p = 0.2\\) and \\(H_1 : p > 0.2\\), where \\(p\\) is the proportion of faulty items in a production line. The test results in \\(H_0\\) being rejected at the 5% significance level. Write a conclusion in context.", workedSolution: { steps: [{ stepNumber: 1, description: "State the conclusion using correct language.", workingLatex: "\\text{There is sufficient evidence at the 5\\% significance level to reject } H_0.", explanation: "" }, { stepNumber: 2, description: "Interpret in context.", workingLatex: "\\text{There is sufficient evidence to suggest that the proportion of faulty items is greater than 0.2.}", explanation: "" }], finalAnswer: "There is sufficient evidence at the 5% significance level to reject \\(H_0\\) and conclude that the proportion of faulty items is greater than 0.2." } },
    { id: "y1ht1-015", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 15", yearCreated: 2026, examStyle: true, marks: 2, difficulty: "Standard", tags: ["p-value", "conclusion"], questionText: "In a hypothesis test at the 5% significance level, the p-value is found to be 0.032. State, with a reason, the conclusion of the test.", workedSolution: { steps: [{ stepNumber: 1, description: "Compare the p-value with the significance level.", workingLatex: "0.032 < 0.05", explanation: "" }, { stepNumber: 2, description: "State the conclusion.", workingLatex: "\\text{Since } 0.032 < 0.05, \\text{ we reject } H_0. \\text{ There is sufficient evidence at the 5\\% level to reject the null hypothesis.}", explanation: "" }], finalAnswer: "Since the p-value (0.032) is less than the significance level (0.05), we reject \\(H_0\\). There is sufficient evidence at the 5% level to reject the null hypothesis." } },
    { id: "y1ht1-016", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 16", yearCreated: 2026, examStyle: true, marks: 2, difficulty: "Standard", tags: ["p-value", "conclusion", "not reject"], questionText: "In a hypothesis test at the 1% significance level, the p-value is found to be 0.038. State, with a reason, the conclusion of the test.", workedSolution: { steps: [{ stepNumber: 1, description: "Compare the p-value with the significance level.", workingLatex: "0.038 > 0.01", explanation: "" }, { stepNumber: 2, description: "State the conclusion.", workingLatex: "\\text{Since } 0.038 > 0.01, \\text{ we do not reject } H_0. \\text{ There is insufficient evidence at the 1\\% level to reject the null hypothesis.}", explanation: "" }], finalAnswer: "Since the p-value (0.038) is greater than the significance level (0.01), we do not reject \\(H_0\\). There is insufficient evidence at the 1% level to reject the null hypothesis." } },
    { id: "y1ht1-017", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 17", yearCreated: 2026, examStyle: true, marks: 2, difficulty: "Standard", tags: ["Type I error", "definition"], questionText: "Define a Type I error in the context of a hypothesis test.", workedSolution: { steps: [{ stepNumber: 1, description: "State the definition.", workingLatex: "\\text{A Type I error occurs when } H_0 \\text{ is rejected when it is in fact true.}", explanation: "" }, { stepNumber: 2, description: "Relate to significance level.", workingLatex: "\\text{The probability of a Type I error is equal to the significance level of the test.}", explanation: "" }], finalAnswer: "A Type I error is rejecting \\(H_0\\) when \\(H_0\\) is actually true. The probability of a Type I error equals the significance level." } },
    { id: "y1ht1-018", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 18", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["Type I error", "context", "significance level"], questionText: "A company claims that 25% of its customers are repeat buyers. A test is carried out at the 5% significance level with \\(H_0 : p = 0.25\\) and \\(H_1 : p > 0.25\\). (a) Describe, in context, what a Type I error would mean. (b) State the probability of a Type I error.", workedSolution: { steps: [{ stepNumber: 1, description: "Describe a Type I error in context.", workingLatex: "\\text{A Type I error would mean concluding that the proportion of repeat buyers is greater than 25\\% when in fact it is 25\\%.}", explanation: "" }, { stepNumber: 2, description: "State the probability.", workingLatex: "P(\\text{Type I error}) = 0.05", explanation: "The probability of a Type I error is equal to the significance level of the test." }], finalAnswer: "(a) A Type I error would be concluding that the proportion of repeat buyers is greater than 25% when it is actually 25%. (b) \\(P(\\text{Type I error}) = 0.05\\)." } },
    { id: "y1ht1-019", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 19", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["conclusion", "in context", "not reject"], questionText: "A doctor claims that a new drug is effective for more than 60% of patients. A hypothesis test is carried out at the 5% significance level with \\(H_0 : p = 0.6\\) and \\(H_1 : p > 0.6\\). The test does not reject \\(H_0\\). Write a conclusion in context.", workedSolution: { steps: [{ stepNumber: 1, description: "State the conclusion.", workingLatex: "\\text{There is insufficient evidence at the 5\\% significance level to reject } H_0.", explanation: "" }, { stepNumber: 2, description: "Interpret in context.", workingLatex: "\\text{There is insufficient evidence to suggest that the drug is effective for more than 60\\% of patients.}", explanation: "" }, { stepNumber: 3, description: "Note an important caveat.", workingLatex: "\\text{This does not prove that the drug is effective for exactly 60\\% of patients; it only means there is not enough evidence to claim the effectiveness exceeds 60\\%.}", explanation: "" }], finalAnswer: "There is insufficient evidence at the 5% significance level to conclude that the drug is effective for more than 60% of patients. This does not prove the effectiveness is exactly 60%." } },
    { id: "y1ht1-020", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 20", yearCreated: 2026, examStyle: true, marks: 2, difficulty: "Standard", tags: ["identify H1", "word problem", "direction"], questionText: "For each of the following scenarios, state whether \\(H_1\\) should use \\(>\\), \\(<\\), or \\(\\neq\\). (a) A farmer suspects that fewer than 40% of his apple trees are affected by a disease. (b) A company wants to test whether a new process has changed the defect rate from the historical rate of 8%.", workedSolution: { steps: [{ stepNumber: 1, description: "Determine H₁ for part (a).", workingLatex: "H_1 : p < 0.4", explanation: "The farmer suspects the proportion is specifically lower than 40%." }, { stepNumber: 2, description: "Determine H₁ for part (b).", workingLatex: "H_1 : p \\neq 0.08", explanation: "The company wants to test whether the defect rate has changed in either direction." }], finalAnswer: "(a) \\(H_1 : p < 0.4\\). (b) \\(H_1 : p \\neq 0.08\\)." } },
    { id: "y1ht1-021", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 21", yearCreated: 2026, examStyle: true, marks: 2, difficulty: "Standard", tags: ["accept H0", "incorrect language"], questionText: "A student writes: 'The test shows that we accept \\(H_0\\).' Explain why this statement is incorrect and write a corrected version.", workedSolution: { steps: [{ stepNumber: 1, description: "Explain why the language is incorrect.", workingLatex: "\\text{We never 'accept' } H_0 \\text{ because failing to reject } H_0 \\text{ does not prove it is true. The data may simply be insufficient to detect a real difference.}", explanation: "" }, { stepNumber: 2, description: "Write the corrected statement.", workingLatex: "\\text{Correct: 'We do not reject } H_0 \\text{' or 'There is insufficient evidence to reject } H_0\\text{.'}", explanation: "" }], finalAnswer: "We should say 'we do not reject \\(H_0\\)' rather than 'we accept \\(H_0\\)', because not rejecting \\(H_0\\) does not prove it is true; it means there is insufficient evidence against it." } },
    { id: "y1ht1-022", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 22", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["comparing significance levels", "5% vs 1%"], questionText: "A hypothesis test is carried out and the p-value is found to be 0.03. (a) State the conclusion at the 5% significance level. (b) State the conclusion at the 1% significance level. (c) Explain why the conclusions differ.", workedSolution: { steps: [{ stepNumber: 1, description: "Conclusion at 5% level.", workingLatex: "0.03 < 0.05, \\text{ so we reject } H_0 \\text{ at the 5\\% significance level.}", explanation: "" }, { stepNumber: 2, description: "Conclusion at 1% level.", workingLatex: "0.03 > 0.01, \\text{ so we do not reject } H_0 \\text{ at the 1\\% significance level.}", explanation: "" }, { stepNumber: 3, description: "Explain why the conclusions differ.", workingLatex: "\\text{The 1\\% level requires stronger evidence (a smaller p-value) to reject } H_0 \\text{ than the 5\\% level. The p-value of 0.03 is small enough to be significant at 5\\% but not at 1\\%.}", explanation: "" }], finalAnswer: "(a) Reject \\(H_0\\) at 5%. (b) Do not reject \\(H_0\\) at 1%. (c) The 1% level requires stronger evidence to reject \\(H_0\\), so a p-value of 0.03 is sufficient at 5% but not at 1%." } },
    { id: "y1ht1-023", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 23", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["hypotheses", "context", "charity", "one-tailed"], questionText: "A charity claims that 45% of adults donate to charity each year. A researcher believes the true proportion is lower. She surveys a random sample of 50 adults. (a) Define the parameter \\(p\\) in context. (b) State \\(H_0\\) and \\(H_1\\). (c) Identify the test statistic.", workedSolution: { steps: [{ stepNumber: 1, description: "Define the parameter.", workingLatex: "p = \\text{the probability that a randomly selected adult donates to charity each year.}", explanation: "" }, { stepNumber: 2, description: "State the hypotheses.", workingLatex: "H_0 : p = 0.45 \\quad H_1 : p < 0.45", explanation: "" }, { stepNumber: 3, description: "Identify the test statistic.", workingLatex: "\\text{The test statistic is the number of adults in the sample of 50 who donate to charity.}", explanation: "" }], finalAnswer: "(a) \\(p\\) is the probability that a randomly selected adult donates to charity each year. (b) \\(H_0 : p = 0.45\\), \\(H_1 : p < 0.45\\). (c) The test statistic is the number of donors in the sample of 50." } },
    { id: "y1ht1-024", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 24", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["conclusion", "in context", "reject", "weather"], questionText: "A weather forecaster claims that the probability of rain on any given day in April is 0.35. A meteorologist tests this at the 5% level with \\(H_0 : p = 0.35\\) and \\(H_1 : p > 0.35\\). The p-value is 0.012. Write the conclusion of the test in context.", workedSolution: { steps: [{ stepNumber: 1, description: "Compare the p-value with the significance level.", workingLatex: "0.012 < 0.05", explanation: "" }, { stepNumber: 2, description: "State the formal conclusion.", workingLatex: "\\text{Reject } H_0.", explanation: "" }, { stepNumber: 3, description: "Write the conclusion in context.", workingLatex: "\\text{There is sufficient evidence at the 5\\% significance level to conclude that the probability of rain on any given day in April is greater than 0.35.}", explanation: "" }], finalAnswer: "Since \\(0.012 < 0.05\\), we reject \\(H_0\\). There is sufficient evidence at the 5% significance level to conclude that the probability of rain in April is greater than 0.35." } },
    { id: "y1ht1-025", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 25", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["hypotheses", "context", "two-tailed", "manufacturing"], questionText: "A machine fills packets of cereal so that the probability of a packet being underweight is 0.05. After maintenance, the factory manager wants to test whether this probability has changed. (a) State \\(H_0\\) and \\(H_1\\), defining \\(p\\). (b) State whether the test is one-tailed or two-tailed, giving a reason. (c) The test is to be carried out at the 10% significance level. For a two-tailed test, explain how the significance level is used.", workedSolution: { steps: [{ stepNumber: 1, description: "State hypotheses.", workingLatex: "\\text{Let } p = \\text{probability a packet is underweight.} \\quad H_0 : p = 0.05, \\quad H_1 : p \\neq 0.05", explanation: "" }, { stepNumber: 2, description: "Identify the test type.", workingLatex: "\\text{Two-tailed, because the manager wants to test whether } p \\text{ has changed in either direction (increased or decreased).}", explanation: "" }, { stepNumber: 3, description: "Explain how the significance level is used in a two-tailed test.", workingLatex: "\\text{The 10\\% significance level is split equally between the two tails, so we reject } H_0 \\text{ if the p-value falls in the lower 5\\% or the upper 5\\%.}", explanation: "" }], finalAnswer: "(a) \\(H_0 : p = 0.05\\), \\(H_1 : p \\neq 0.05\\). (b) Two-tailed, because the manager tests for change in either direction. (c) The 10% level is split into 5% in each tail." } },
    { id: "y1ht1-026", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 26", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["Type I error", "context", "probability"], questionText: "A test is carried out at the 2% significance level to determine whether a coin is biased towards tails, using \\(H_0 : p = 0.5\\) and \\(H_1 : p < 0.5\\), where \\(p\\) is the probability of heads. (a) Describe what a Type I error would mean in this context. (b) State \\(P(\\text{Type I error})\\). (c) Explain why a smaller significance level reduces the chance of a Type I error.", workedSolution: { steps: [{ stepNumber: 1, description: "Describe the Type I error in context.", workingLatex: "\\text{A Type I error means concluding that the coin is biased towards tails when in fact the coin is fair.}", explanation: "" }, { stepNumber: 2, description: "State the probability.", workingLatex: "P(\\text{Type I error}) = 0.02", explanation: "" }, { stepNumber: 3, description: "Explain the effect of a smaller significance level.", workingLatex: "\\text{A smaller significance level requires a more extreme result to reject } H_0, \\text{ so it is harder to reject a true } H_0, \\text{ which reduces the chance of a Type I error.}", explanation: "" }], finalAnswer: "(a) Concluding the coin is biased towards tails when it is actually fair. (b) \\(P(\\text{Type I error}) = 0.02\\). (c) A smaller significance level requires stronger evidence to reject \\(H_0\\), reducing the chance of incorrectly rejecting a true \\(H_0\\)." } },
    { id: "y1ht1-027", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 27", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["p-value", "conclusion", "interpretation", "vaccine"], questionText: "A pharmaceutical company tests whether a new vaccine is effective for more than 70% of patients. The hypotheses are \\(H_0 : p = 0.7\\) and \\(H_1 : p > 0.7\\). The p-value from the test is 0.047. (a) At the 5% significance level, state the conclusion. (b) At the 1% significance level, state the conclusion. (c) Explain what the p-value of 0.047 represents.", workedSolution: { steps: [{ stepNumber: 1, description: "Conclusion at 5% level.", workingLatex: "0.047 < 0.05 \\Rightarrow \\text{Reject } H_0.", explanation: "" }, { stepNumber: 2, description: "Conclusion at 1% level.", workingLatex: "0.047 > 0.01 \\Rightarrow \\text{Do not reject } H_0.", explanation: "" }, { stepNumber: 3, description: "Explain the meaning of the p-value.", workingLatex: "\\text{The p-value of 0.047 is the probability of observing a result as extreme as, or more extreme than, the observed data, assuming } H_0 \\text{ is true.}", explanation: "" }], finalAnswer: "(a) Reject \\(H_0\\) at 5%. (b) Do not reject \\(H_0\\) at 1%. (c) The p-value of 0.047 is the probability of obtaining the observed result (or more extreme) if \\(H_0\\) were true." } },
    { id: "y1ht1-028", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 28", yearCreated: 2026, examStyle: true, marks: 3, difficulty: "Standard", tags: ["hypotheses", "context", "election", "one-tailed"], questionText: "Before an election, a political party claimed that more than 50% of voters would support them. A polling organisation surveys 100 randomly selected voters. (a) State suitable hypotheses for a test of the party's claim. (b) Of the 100 voters surveyed, 57 say they support the party. State the test statistic. (c) The p-value for this test is 0.097. At the 5% significance level, state the conclusion in context.", workedSolution: { steps: [{ stepNumber: 1, description: "State the hypotheses.", workingLatex: "H_0 : p = 0.5 \\quad H_1 : p > 0.5", explanation: "where p is the probability that a randomly selected voter supports the party." }, { stepNumber: 2, description: "State the test statistic.", workingLatex: "\\text{The test statistic is 57 (the number of voters in the sample who support the party).}", explanation: "" }, { stepNumber: 3, description: "State the conclusion.", workingLatex: "0.097 > 0.05 \\Rightarrow \\text{Do not reject } H_0. \\text{ There is insufficient evidence at the 5\\% significance level to support the party's claim that more than 50\\% of voters support them.}", explanation: "" }], finalAnswer: "(a) \\(H_0 : p = 0.5\\), \\(H_1 : p > 0.5\\). (b) Test statistic = 57. (c) Since \\(0.097 > 0.05\\), do not reject \\(H_0\\). There is insufficient evidence to support the claim that more than 50% of voters support the party." } },
    { id: "y1ht1-029", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 29", yearCreated: 2026, examStyle: true, marks: 5, difficulty: "Challenge", tags: ["multi-part", "hypotheses", "test type", "conclusion", "interpretation"], questionText: "A spinner has five equal sections numbered 1 to 5. A player suspects that the spinner is biased so that it lands on 5 more often than it should. She spins it 40 times and it lands on 5 a total of 14 times. A hypothesis test is carried out at the 5% significance level and the p-value is found to be 0.018. (a) State \\(H_0\\) and \\(H_1\\), defining \\(p\\). (b) State whether this is a one-tailed or two-tailed test. (c) State the test statistic. (d) Write a conclusion in context. (e) State what a Type I error would mean in this context.", workedSolution: { steps: [{ stepNumber: 1, description: "Define p and state hypotheses.", workingLatex: "p = \\text{probability of landing on 5.} \\quad H_0 : p = 0.2, \\quad H_1 : p > 0.2", explanation: "" }, { stepNumber: 2, description: "Identify the test type.", workingLatex: "\\text{One-tailed (upper), because the player suspects the spinner lands on 5 more often.}", explanation: "" }, { stepNumber: 3, description: "State the test statistic.", workingLatex: "\\text{The test statistic is 14 (the number of times the spinner landed on 5 in 40 spins).}", explanation: "" }, { stepNumber: 4, description: "Write the conclusion.", workingLatex: "0.018 < 0.05 \\Rightarrow \\text{Reject } H_0. \\text{ There is sufficient evidence at the 5\\% level to conclude that the spinner is biased towards landing on 5.}", explanation: "" }, { stepNumber: 5, description: "Describe the Type I error in context.", workingLatex: "\\text{A Type I error would mean concluding the spinner is biased towards 5 when it is actually fair.}", explanation: "" }], finalAnswer: "(a) \\(H_0 : p = 0.2\\), \\(H_1 : p > 0.2\\). (b) One-tailed. (c) Test statistic = 14. (d) Reject \\(H_0\\); sufficient evidence the spinner is biased towards 5. (e) Concluding the spinner is biased when it is actually fair." } },
    { id: "y1ht1-030", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 30", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Challenge", tags: ["significance level", "Type I error", "relationship"], questionText: "Explain the relationship between the significance level of a hypothesis test and the probability of making a Type I error. In your answer, explain why choosing a very small significance level is not always desirable.", workedSolution: { steps: [{ stepNumber: 1, description: "State the relationship.", workingLatex: "\\text{The significance level } \\alpha \\text{ is exactly equal to the probability of a Type I error: } P(\\text{reject } H_0 \\mid H_0 \\text{ true}) = \\alpha.", explanation: "" }, { stepNumber: 2, description: "Explain why the significance level equals the Type I error probability.", workingLatex: "\\text{By definition, we reject } H_0 \\text{ when the p-value is less than } \\alpha. \\text{ If } H_0 \\text{ is true, the probability of obtaining such an extreme result is exactly } \\alpha.", explanation: "" }, { stepNumber: 3, description: "Explain the downside of a very small significance level.", workingLatex: "\\text{A very small } \\alpha \\text{ makes it harder to reject } H_0, \\text{ increasing the probability of a Type II error (failing to reject } H_0 \\text{ when it is false).}", explanation: "There is a trade-off: reducing the chance of a Type I error increases the chance of a Type II error." }], finalAnswer: "The probability of a Type I error equals the significance level \\(\\alpha\\). However, choosing a very small \\(\\alpha\\) makes it harder to reject \\(H_0\\), increasing the risk of a Type II error (failing to detect a real effect)." } },
    { id: "y1ht1-031", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 31", yearCreated: 2026, examStyle: true, marks: 4, difficulty: "Challenge", tags: ["reject H0", "H1 true", "interpretation"], questionText: "A test at the 5% significance level rejects \\(H_0\\). A student concludes: 'This proves that \\(H_1\\) is true.' Explain why this conclusion is not correct.", workedSolution: { steps: [{ stepNumber: 1, description: "Explain what rejecting H₀ actually means.", workingLatex: "\\text{Rejecting } H_0 \\text{ means the observed data are unlikely to have occurred if } H_0 \\text{ were true. It does not prove } H_1 \\text{ is true.}", explanation: "" }, { stepNumber: 2, description: "Explain the possibility of a Type I error.", workingLatex: "\\text{There is a 5\\% chance that } H_0 \\text{ has been rejected even though it is true (a Type I error).}", explanation: "" }, { stepNumber: 3, description: "Provide the correct interpretation.", workingLatex: "\\text{The correct statement is: there is sufficient evidence at the 5\\% level to reject } H_0 \\text{ in favour of } H_1. \\text{ This is not the same as proving } H_1.", explanation: "" }], finalAnswer: "Rejecting \\(H_0\\) does not prove \\(H_1\\) is true. There is a 5% probability that \\(H_0\\) was rejected incorrectly (Type I error). The correct interpretation is that there is sufficient evidence to reject \\(H_0\\) in favour of \\(H_1\\), not that \\(H_1\\) has been proved." } },
    { id: "y1ht1-032", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 32", yearCreated: 2026, examStyle: true, marks: 5, difficulty: "Challenge", tags: ["Type I", "Type II", "trade-off", "significance level"], questionText: "Discuss the trade-off between Type I and Type II errors when choosing the significance level for a hypothesis test. Use an example involving a medical test to illustrate your answer.", workedSolution: { steps: [{ stepNumber: 1, description: "Define both types of error.", workingLatex: "\\text{Type I error: rejecting } H_0 \\text{ when it is true. Type II error: not rejecting } H_0 \\text{ when it is false.}", explanation: "" }, { stepNumber: 2, description: "Describe the trade-off.", workingLatex: "\\text{Decreasing the significance level (e.g. from 5\\% to 1\\%) reduces } P(\\text{Type I error}) \\text{ but increases } P(\\text{Type II error}), \\text{ and vice versa.}", explanation: "" }, { stepNumber: 3, description: "Give a medical example.", workingLatex: "\\text{Suppose a test determines whether a patient has a disease. } H_0 : \\text{patient is healthy, } H_1 : \\text{patient has the disease.}", explanation: "" }, { stepNumber: 4, description: "Explain consequences in the medical context.", workingLatex: "\\text{Type I error: telling a healthy patient they have the disease (unnecessary worry and treatment). Type II error: telling a sick patient they are healthy (missing the disease).}", explanation: "" }, { stepNumber: 5, description: "Explain the significance level choice.", workingLatex: "\\text{In a medical context, missing the disease (Type II) could be life-threatening, so a higher significance level may be preferred to reduce Type II errors, even though this increases the risk of Type I errors.}", explanation: "" }], finalAnswer: "Reducing the significance level decreases the chance of a Type I error but increases the chance of a Type II error. In a medical test, a Type II error (missing a disease) may be more dangerous than a Type I error (a false alarm), so a higher significance level might be chosen to reduce the risk of missing the disease." } },
    { id: "y1ht1-033", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 33", yearCreated: 2026, examStyle: true, marks: 5, difficulty: "Challenge", tags: ["different significance levels", "same data", "comparing conclusions"], questionText: "A hypothesis test is carried out on the same data at both the 5% and 1% significance levels. The hypotheses are \\(H_0 : p = 0.3\\) and \\(H_1 : p > 0.3\\). At the 5% level, \\(H_0\\) is rejected, but at the 1% level, \\(H_0\\) is not rejected. (a) What can you deduce about the p-value? (b) Explain why the two tests produce different conclusions. (c) Which conclusion should a researcher report, and why?", workedSolution: { steps: [{ stepNumber: 1, description: "Deduce the range of the p-value.", workingLatex: "0.01 < \\text{p-value} < 0.05", explanation: "The p-value must be less than 0.05 (since H₀ is rejected at 5%) but greater than 0.01 (since H₀ is not rejected at 1%)." }, { stepNumber: 2, description: "Explain why conclusions differ.", workingLatex: "\\text{The 1\\% level requires stronger evidence (a smaller p-value) to reject } H_0. \\text{ The p-value is small enough to be significant at 5\\% but not at 1\\%.}", explanation: "" }, { stepNumber: 3, description: "Advise on which conclusion to report.", workingLatex: "\\text{The researcher should report the conclusion at the significance level chosen before the data were collected.}", explanation: "The significance level should be set in advance to avoid bias. Choosing the level after seeing the results would be inappropriate." }], finalAnswer: "(a) \\(0.01 < \\text{p-value} < 0.05\\). (b) The 1% level requires stronger evidence; the p-value is significant at 5% but not at 1%. (c) The researcher should report the conclusion at the pre-specified significance level." } },
    { id: "y1ht1-034", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 34", yearCreated: 2026, examStyle: true, marks: 5, difficulty: "Challenge", tags: ["critique", "student error", "incorrect setup"], questionText: "A student is testing whether a coin is fair. She flips it 20 times and gets 14 heads. She writes the following:\n\n\\(H_0 : p = 0.7\\), \\(H_1 : p = 0.5\\)\n\nIdentify and correct all errors in the student's hypothesis test setup.", workedSolution: { steps: [{ stepNumber: 1, description: "Identify the first error: the null hypothesis.", workingLatex: "H_0 \\text{ should state the value under the assumption of no bias. For a fair coin, } H_0 : p = 0.5.", explanation: "The null hypothesis should represent the default assumption (the coin is fair), not the observed proportion." }, { stepNumber: 2, description: "Identify the second error: the alternative hypothesis.", workingLatex: "H_1 \\text{ should not state a specific value. It should indicate the direction of the suspected bias.}", explanation: "The alternative hypothesis specifies a direction or inequality, not a single value." }, { stepNumber: 3, description: "Identify the third error: the direction of the test.", workingLatex: "\\text{Since 14 out of 20 is more than expected for a fair coin, if the student suspects bias towards heads, then } H_1 : p > 0.5.", explanation: "" }, { stepNumber: 4, description: "Write the corrected hypotheses.", workingLatex: "H_0 : p = 0.5, \\quad H_1 : p > 0.5 \\quad \\text{(if testing for bias towards heads)}", explanation: "Alternatively, if the student had no prior suspicion of direction, H₁ : p ≠ 0.5 for a two-tailed test." }], finalAnswer: "Errors: (1) \\(H_0\\) should be \\(p = 0.5\\) (fair coin), not 0.7. (2) \\(H_1\\) should be an inequality, not a specific value. (3) Corrected: \\(H_0 : p = 0.5\\), \\(H_1 : p > 0.5\\) (or \\(H_1 : p \\neq 0.5\\) for a two-tailed test)." } },
    { id: "y1ht1-035", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 35", yearCreated: 2026, examStyle: true, marks: 5, difficulty: "Challenge", tags: ["show that", "Type I error", "significance level", "proof"], questionText: "In a hypothesis test, the significance level is \\(\\alpha\\). Explain why the probability of a Type I error is equal to \\(\\alpha\\). You may assume that the test statistic has a known distribution under \\(H_0\\).", workedSolution: { steps: [{ stepNumber: 1, description: "Define a Type I error.", workingLatex: "\\text{A Type I error occurs when } H_0 \\text{ is rejected given that } H_0 \\text{ is true.}", explanation: "" }, { stepNumber: 2, description: "State the decision rule.", workingLatex: "\\text{We reject } H_0 \\text{ when the p-value} < \\alpha, \\text{ i.e. when the test statistic falls in the critical region.}", explanation: "" }, { stepNumber: 3, description: "Calculate the probability of the test statistic falling in the critical region when H₀ is true.", workingLatex: "P(\\text{test statistic in critical region} \\mid H_0 \\text{ true}) = \\alpha", explanation: "The critical region is defined as the set of values for which we reject H₀, and by construction this region is chosen so that its probability under H₀ is exactly α." }, { stepNumber: 4, description: "Conclude the argument.", workingLatex: "P(\\text{Type I error}) = P(\\text{reject } H_0 \\mid H_0 \\text{ true}) = P(\\text{test statistic in critical region} \\mid H_0 \\text{ true}) = \\alpha", explanation: "" }], finalAnswer: "By definition, the critical region is chosen so that \\(P(\\text{test statistic in critical region} \\mid H_0 \\text{ true}) = \\alpha\\). Since a Type I error is rejecting \\(H_0\\) when it is true, \\(P(\\text{Type I error}) = \\alpha\\)." } },
    { id: "y1ht1-036", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 36", yearCreated: 2026, examStyle: true, marks: 6, difficulty: "Challenge", tags: ["multi-part", "exam-style", "all concepts", "sports"], questionText: "A tennis player claims that she wins 65% of her service games. Her coach suspects the true proportion is lower. Over a season, the coach records the outcomes of 50 randomly selected service games and finds that she won 27 of them. The coach carries out a hypothesis test at the 5% significance level and obtains a p-value of 0.041. (a) Define the parameter \\(p\\) in context. (b) State \\(H_0\\) and \\(H_1\\). (c) State whether the test is one-tailed or two-tailed. (d) State the test statistic. (e) Write the conclusion in context. (f) State the probability of a Type I error and describe what it would mean in context.", workedSolution: { steps: [{ stepNumber: 1, description: "Define p.", workingLatex: "p = \\text{the probability that the player wins a randomly selected service game.}", explanation: "" }, { stepNumber: 2, description: "State the hypotheses.", workingLatex: "H_0 : p = 0.65 \\quad H_1 : p < 0.65", explanation: "" }, { stepNumber: 3, description: "Identify the test type.", workingLatex: "\\text{One-tailed (lower), because the coach suspects the proportion is lower.}", explanation: "" }, { stepNumber: 4, description: "State the test statistic.", workingLatex: "\\text{The test statistic is 27 (the number of service games won out of 50).}", explanation: "" }, { stepNumber: 5, description: "Write the conclusion.", workingLatex: "0.041 < 0.05 \\Rightarrow \\text{Reject } H_0. \\text{ There is sufficient evidence at the 5\\% level to conclude that the player wins fewer than 65\\% of her service games.}", explanation: "" }, { stepNumber: 6, description: "State the Type I error probability and meaning.", workingLatex: "P(\\text{Type I error}) = 0.05. \\text{ This would mean concluding that the player wins fewer than 65\\% of her service games when she actually does win 65\\%.}", explanation: "" }], finalAnswer: "(a) \\(p\\) = probability she wins a service game. (b) \\(H_0 : p = 0.65\\), \\(H_1 : p < 0.65\\). (c) One-tailed. (d) Test statistic = 27. (e) Reject \\(H_0\\); sufficient evidence she wins fewer than 65%. (f) \\(P(\\text{Type I error}) = 0.05\\); concluding she wins fewer than 65% when she actually wins 65%." } },
    { id: "y1ht1-037", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 37", yearCreated: 2026, examStyle: true, marks: 6, difficulty: "Challenge", tags: ["multi-part", "exam-style", "all concepts", "medicine"], questionText: "A standard treatment for a condition is effective for 40% of patients. A new treatment is developed and a doctor wants to test whether it is more effective. 80 patients are given the new treatment and 39 respond positively. A hypothesis test is carried out at the 10% significance level and the p-value is 0.102. (a) State \\(H_0\\) and \\(H_1\\), defining \\(p\\). (b) State the test statistic. (c) Write the conclusion in context. (d) The doctor repeats the test at the 5% significance level. Without further calculation, state the conclusion and give a reason. (e) Describe what a Type I error would mean in this context and state its probability when testing at the 10% level.", workedSolution: { steps: [{ stepNumber: 1, description: "State hypotheses.", workingLatex: "\\text{Let } p = \\text{probability a patient responds positively to the new treatment.} \\quad H_0 : p = 0.4, \\quad H_1 : p > 0.4", explanation: "" }, { stepNumber: 2, description: "State the test statistic.", workingLatex: "\\text{The test statistic is 39 (the number of patients who responded positively out of 80).}", explanation: "" }, { stepNumber: 3, description: "Write the conclusion at 10% level.", workingLatex: "0.102 > 0.10 \\Rightarrow \\text{Do not reject } H_0. \\text{ There is insufficient evidence at the 10\\% level to conclude that the new treatment is more effective than the standard treatment.}", explanation: "" }, { stepNumber: 4, description: "State the conclusion at 5% level.", workingLatex: "\\text{Since } 0.102 > 0.10 > 0.05, \\text{ the p-value is also greater than 0.05. Therefore we still do not reject } H_0.", explanation: "If the result is not significant at a higher significance level, it cannot be significant at a lower one." }, { stepNumber: 5, description: "Describe Type I error and state its probability.", workingLatex: "\\text{A Type I error would mean concluding the new treatment is more effective than the standard (i.e. } p > 0.4 \\text{) when in fact it is equally effective (} p = 0.4 \\text{).} \\quad P(\\text{Type I error}) = 0.10.", explanation: "" }], finalAnswer: "(a) \\(H_0 : p = 0.4\\), \\(H_1 : p > 0.4\\). (b) Test statistic = 39. (c) Do not reject \\(H_0\\); insufficient evidence the new treatment is more effective. (d) Still do not reject \\(H_0\\), since \\(0.102 > 0.05\\). (e) Concluding the new treatment is more effective when it is not; \\(P(\\text{Type I error}) = 0.10\\)." } },
    { id: "y1ht1-038", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 38", yearCreated: 2026, examStyle: true, marks: 5, difficulty: "Challenge", tags: ["critique", "student error", "conclusion language"], questionText: "A student carries out a hypothesis test with \\(H_0 : p = 0.5\\) and \\(H_1 : p \\neq 0.5\\) at the 5% significance level. The p-value is 0.062. The student writes:\n\n'Since 0.062 > 0.05, we accept \\(H_0\\). This proves the coin is fair.'\n\nIdentify and explain all the errors in the student's conclusion.", workedSolution: { steps: [{ stepNumber: 1, description: "Identify the first error: 'accept H₀'.", workingLatex: "\\text{We never 'accept' } H_0. \\text{ The correct language is 'we do not reject } H_0 \\text{' or 'there is insufficient evidence to reject } H_0\\text{.'}", explanation: "" }, { stepNumber: 2, description: "Identify the second error: 'proves the coin is fair'.", workingLatex: "\\text{Not rejecting } H_0 \\text{ does not prove } H_0 \\text{ is true. It only means there is insufficient evidence against it.}", explanation: "" }, { stepNumber: 3, description: "Identify a potential third issue: two-tailed comparison.", workingLatex: "\\text{For a two-tailed test, the student should check whether the p-value (0.062) is less than 0.05. The comparison is correct, but the student should be aware that the significance level is not split — the p-value already accounts for both tails.}", explanation: "" }, { stepNumber: 4, description: "Write a corrected conclusion.", workingLatex: "\\text{Since } 0.062 > 0.05, \\text{ there is insufficient evidence at the 5\\% significance level to reject } H_0. \\text{ There is insufficient evidence to conclude that the coin is biased.}", explanation: "" }], finalAnswer: "Errors: (1) Should say 'do not reject \\(H_0\\)' not 'accept \\(H_0\\)'. (2) Not rejecting \\(H_0\\) does not prove the coin is fair; it means there is insufficient evidence of bias. Corrected: 'There is insufficient evidence at the 5% level to conclude the coin is biased.'" } },
    { id: "y1ht1-039", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 39", yearCreated: 2026, examStyle: true, marks: 6, difficulty: "Challenge", tags: ["multi-part", "exam-style", "all concepts", "ecology"], questionText: "An ecologist believes that 20% of a particular species of bird nests in urban areas. After a change in land use, she suspects the proportion may have changed. She surveys 60 nesting sites and finds that 18 are in urban areas. A hypothesis test at the 5% significance level gives a p-value of 0.076. (a) State \\(H_0\\) and \\(H_1\\), defining \\(p\\). (b) Explain why a two-tailed test is appropriate. (c) State the test statistic. (d) Write the conclusion in context. (e) State \\(P(\\text{Type I error})\\) and explain its meaning. (f) If the ecologist repeated the test at the 10% significance level, state, with a reason, whether the conclusion would change.", workedSolution: { steps: [{ stepNumber: 1, description: "State hypotheses.", workingLatex: "\\text{Let } p = \\text{probability a nesting site is in an urban area.} \\quad H_0 : p = 0.2, \\quad H_1 : p \\neq 0.2", explanation: "" }, { stepNumber: 2, description: "Explain why two-tailed.", workingLatex: "\\text{The ecologist suspects the proportion may have changed but does not specify whether it has increased or decreased, so both directions are considered.}", explanation: "" }, { stepNumber: 3, description: "State the test statistic.", workingLatex: "\\text{The test statistic is 18 (the number of urban nesting sites out of 60).}", explanation: "" }, { stepNumber: 4, description: "Write the conclusion at 5%.", workingLatex: "0.076 > 0.05 \\Rightarrow \\text{Do not reject } H_0. \\text{ There is insufficient evidence at the 5\\% level to conclude that the proportion of nesting sites in urban areas has changed from 20\\%.}", explanation: "" }, { stepNumber: 5, description: "State P(Type I error) and its meaning.", workingLatex: "P(\\text{Type I error}) = 0.05. \\text{ A Type I error would be concluding the proportion has changed from 20\\% when it has not.}", explanation: "" }, { stepNumber: 6, description: "Consider the 10% significance level.", workingLatex: "0.076 < 0.10 \\Rightarrow \\text{At the 10\\% level, we would reject } H_0. \\text{ The conclusion would change: there would be sufficient evidence to conclude the proportion has changed.}", explanation: "" }], finalAnswer: "(a) \\(H_0 : p = 0.2\\), \\(H_1 : p \\neq 0.2\\). (b) Two-tailed because the direction of change is not specified. (c) Test statistic = 18. (d) Do not reject \\(H_0\\) at 5%; insufficient evidence of a change. (e) \\(P(\\text{Type I error}) = 0.05\\); concluding the proportion changed when it has not. (f) At 10%, reject \\(H_0\\) since \\(0.076 < 0.10\\); the conclusion would change." } },
    { id: "y1ht1-040", topicRef: "y1ht1", topicTitle: "Hypothesis Test Concepts 40", yearCreated: 2026, examStyle: true, marks: 6, difficulty: "Challenge", tags: ["multi-part", "exam-style", "all concepts", "quality control"], questionText: "A factory produces bolts and the historical defect rate is 5%. After installing new machinery, the quality manager wants to test whether the defect rate has decreased. A random sample of 100 bolts is taken and 2 are found to be defective. A hypothesis test at the 5% significance level gives a p-value of 0.118. (a) State \\(H_0\\) and \\(H_1\\), defining \\(p\\). (b) State whether this is a one-tailed or two-tailed test. (c) State the test statistic. (d) Write the conclusion in context. (e) The quality manager says: 'Since we did not reject \\(H_0\\), the defect rate is definitely still 5%.' Explain why this statement is incorrect. (f) If the significance level were changed to 10%, and the p-value remained 0.118, would the conclusion change? Justify your answer.", workedSolution: { steps: [{ stepNumber: 1, description: "State hypotheses.", workingLatex: "\\text{Let } p = \\text{probability a randomly selected bolt is defective.} \\quad H_0 : p = 0.05, \\quad H_1 : p < 0.05", explanation: "" }, { stepNumber: 2, description: "Identify the test type.", workingLatex: "\\text{One-tailed (lower), because the manager suspects the defect rate has decreased.}", explanation: "" }, { stepNumber: 3, description: "State the test statistic.", workingLatex: "\\text{The test statistic is 2 (the number of defective bolts in the sample of 100).}", explanation: "" }, { stepNumber: 4, description: "Write the conclusion.", workingLatex: "0.118 > 0.05 \\Rightarrow \\text{Do not reject } H_0. \\text{ There is insufficient evidence at the 5\\% level to conclude that the defect rate has decreased from 5\\%.}", explanation: "" }, { stepNumber: 5, description: "Explain why the manager's statement is incorrect.", workingLatex: "\\text{Not rejecting } H_0 \\text{ does not prove that } p = 0.05. \\text{ It means there is insufficient evidence to conclude } p < 0.05. \\text{ The true defect rate could be lower than 5\\% but the sample was too small to detect it.}", explanation: "" }, { stepNumber: 6, description: "Consider the 10% significance level.", workingLatex: "0.118 > 0.10 \\Rightarrow \\text{We would still not reject } H_0 \\text{ at the 10\\% level. The conclusion would not change.}", explanation: "" }], finalAnswer: "(a) \\(H_0 : p = 0.05\\), \\(H_1 : p < 0.05\\). (b) One-tailed. (c) Test statistic = 2. (d) Do not reject \\(H_0\\); insufficient evidence the defect rate has decreased. (e) Not rejecting \\(H_0\\) does not prove \\(p = 0.05\\); the sample may be too small to detect a difference. (f) No change, since \\(0.118 > 0.10\\)." } },
];
